#include <bits/stdc++.h>
using namespace std;

const int N=110;

int n,m,f[N][N];
long long g[N][N];
double val[N];

int main(){
    memset(f,0x3f,sizeof(f));
    scanf("%d%d",&n,&m);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        f[u][v]=f[v][u]=w;
        g[u][v]=g[v][u]=1;
    }
    for(int i=1;i<=n;i++)
        f[i][i]=0;
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++){
                if(f[i][k]+f[k][j]<f[i][j])
                    f[i][j]=f[i][k]+f[k][j],g[i][j]=g[i][k]*g[k][j];
                else if(f[i][k]+f[k][j]==f[i][j])
                    f[i][j]=f[i][k]+f[k][j],g[i][j]+=g[i][k]*g[k][j];
            }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            for(int k=1;k<=n;k++)
                if(f[j][i]+f[i][k]==f[j][k] && i!=j && i!=k && j!=k)
                    val[i]+=1.0*g[j][i]*g[i][k]/g[j][k];
    for(int i=1;i<=n;i++)
        printf("%.3lf\n",val[i]);
    return 0;
}
